import{_ as i,o as s,c as t,a2 as e}from"./chunks/framework.m9rfQn3T.js";const c=JSON.parse('{"title":"XSS攻击","description":"","frontmatter":{"title":"XSS攻击","date":"2021-06-17T17:18:24.000Z","permalink":"/pages/62502f3dd8041/","categories":["面试题","浏览器"],"tags":[null]},"headers":[],"relativePath":"10.面试题/35.浏览器/01.XSS攻击.md","filePath":"10.面试题/35.浏览器/01.XSS攻击.md","lastUpdated":1782538095000}'),l={name:"10.面试题/35.浏览器/01.XSS攻击.md"};function p(h,a,r,n,o,k){return s(),t("div",null,[...a[0]||(a[0]=[e('<p><code>XSS</code>就是<code>Cross Site Scripting</code>,为了和 css 攻击区分开，所以叫 XSS</p><p>XSS 攻击是指浏览器中执行恶意脚本(无论是跨域还是同域)，从而拿到用户的信息并进行操作。</p><ul><li>窃取 Cookie</li><li>监听用户行为，比如输入账号密码后直接发送到黑客服务器</li><li>修改 DOM 伪造登录表单</li><li>在页面中生成浮窗广告</li></ul><p>&lt;!--more--&gt;</p><p>XSS 分为三种方式</p><h2 id="存储型" tabindex="-1">存储型 <a class="header-anchor" href="#存储型" aria-label="Permalink to &quot;存储型&quot;">​</a></h2><p>存储型，顾名思义就是将恶意脚本存储了起来，确实，存储型的 XSS 将脚本存储到了服务端的数据库，然后在客户端执行这些脚本，从而达到攻击的效果。</p><p>常见的场景是留言评论区提交一段脚本代码，如果前后端没有做好转义的工作，那评论内容存到了数据库，在页面渲染过程中直接执行, 相当于执行一段未知逻辑的 JS 代码，是非常恐怖的。这就是存储型的 XSS 攻击</p><h2 id="反射型" tabindex="-1">反射型 <a class="header-anchor" href="#反射型" aria-label="Permalink to &quot;反射型&quot;">​</a></h2><p>反射型 XSS 指的是恶意脚本作为网络请求的一部分</p><blockquote><p><a href="http://www.shenzjd.com?q=" target="_blank" rel="noreferrer">http://www.shenzjd.com?q=</a>&lt;script&gt;alert(&quot;你完蛋了&quot;)&lt;/script&gt;</p></blockquote><p>这样，在服务器端会拿到 q 参数,然后将内容返回给浏览器端，浏览器将这些内容作为 HTML 的一部分解析，发现是一个脚本，直接执行，这样就被攻击了。</p><p>之所以叫它反射型, 是因为恶意脚本是通过作为网络请求的参数，经过服务器，然后再反射到 HTML 文档中，执行解析。和存储型不一样的是，服务器并不会存储这些恶意脚本</p><h2 id="文档型" tabindex="-1">文档型 <a class="header-anchor" href="#文档型" aria-label="Permalink to &quot;文档型&quot;">​</a></h2><p>文档型的 XSS 攻击并不会经过服务端，而是作为中间人的角色，在数据传输过程劫持到网络数据包，然后修改里面的 html 文档！</p><p>这样的劫持方式包括 WIFI 路由器劫持或者本地恶意软件等(dns 篡改)</p><h2 id="防范措施" tabindex="-1">防范措施 <a class="header-anchor" href="#防范措施" aria-label="Permalink to &quot;防范措施&quot;">​</a></h2><p>一个共同点: 都是让恶意脚本直接能在浏览器中执行</p><p>那么要防范它，就是要避免这些脚本代码的执行</p><p>一个信念 千万不要相信任何用户的输入！</p><p>无论是在前端和服务端，都要对用户的输入进行转码或者过滤。</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;alert(&#39;你完蛋了&#39;)&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="转码" tabindex="-1">转码 <a class="header-anchor" href="#转码" aria-label="Permalink to &quot;转码&quot;">​</a></h3><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lt;script</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">alert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">39</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;你完蛋了</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">39</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">script</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gt;</span></span></code></pre></div><p>这样的代码在 html 解析的过程中是无法执行的。</p><p>当然也可以利用关键词过滤的方式，将 script 标签给删除。</p><h3 id="利用-csp" tabindex="-1">利用 CSP <a class="header-anchor" href="#利用-csp" aria-label="Permalink to &quot;利用 CSP&quot;">​</a></h3><p>CSP，即浏览器中的内容安全策略，它的核心思想就是服务器决定浏览器加载哪些资源，具体来说可以完成以下功能</p><ul><li>限制其他域下的资源加载</li><li>禁止向其它域提交数据</li><li>提供上报机制，能帮助我们及时发现 XSS 攻击</li></ul><h3 id="利用-httponly" tabindex="-1">利用 HttpOnly <a class="header-anchor" href="#利用-httponly" aria-label="Permalink to &quot;利用 HttpOnly&quot;">​</a></h3><p>很多 XSS 攻击脚本都是用来窃取 Cookie, 而设置 Cookie 的 HttpOnly 属性后，JavaScript 便无法读取 Cookie 的值。这样也能很好的防范 XSS 攻击。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>XSS 攻击是指浏览器中执行恶意脚本, 然后拿到用户的信息进行操作。主要分为存储型、反射型和文档型。防范的措施包括:</p><p>一个信念: 不要相信用户的输入，对输入内容转码或者过滤，让其不可执行。 两个利用: 利用 CSP，利用 Cookie 的 HttpOnly 属性。</p><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://sanyuan0704.top/my_blog/blogs/browser/browser-security/001.html" target="_blank" rel="noreferrer">https://sanyuan0704.top/my_blog/blogs/browser/browser-security/001.html</a></li></ul>',36)])])}const E=i(l,[["render",p]]);export{c as __pageData,E as default};
